// Module ESM exécuté dans la sandbox Web Worker (pas de DOM, pas de réseau direct).
// providers.complete(prompt) est la seule voie d'appel LLM autorisée.
export async function run({ texteFeuille, dateFeuille, referentiel, providers, prompts }) {
  const passes = [];
  for (const pole of referentiel.poles) {
    const liste = referentiel.competences
      .filter((c) => c.pole === pole.num)
      .map((c) => `${c.code} — ${c.nom}`)
      .join(' ; ');
    const texte = prompts['extraction-pole']
      .replaceAll('{{pole_num}}', String(pole.num))
      .replaceAll('{{pole_nom}}', pole.nom)
      .replaceAll('{{date_feuille}}', dateFeuille)
      .replaceAll('{{competences_liste}}', liste)
      .replaceAll('{{texte_feuille}}', texteFeuille);
    passes.push(JSON.parse(await providers.complete(texte)));
  }
  const kairos = JSON.parse(await providers.complete(
    prompts['kairos']
      .replaceAll('{{date_feuille}}', dateFeuille)
      .replaceAll('{{nb_poles}}', String(referentiel.poles.length))
      .replaceAll('{{verdicts_json}}', JSON.stringify(passes))
  ));
  return { schemaVersion: '1.0.0', kind: 'cartographie-jour', date: dateFeuille, poles: passes, kairos };
}
